package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.asn.AsnTransportQueryApplicationService;import jakarta.servlet.http.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1/asns/{asnId}/transport-trails")public class AsnTransportTrailController {private final AsnTransportQueryApplicationService service;public AsnTransportTrailController(AsnTransportQueryApplicationService service){this.service=service;}@GetMapping public ApiResponse<List<AsnTransportQueryApplicationService.Trail>> list(@PathVariable long asnId,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.trails(asnId,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}}
